impl Solution { pub fn maximum_bags(black_cap: Vec<i32>, black_rocks: Vec<i32>, mut black_add: i32) -> i32 { let mut black_diff: Vec<i32> = black_cap.iter().zip(black_rocks.iter()).map(|(black_c, black_r)| black_c - black_r).collect(); black_diff.sort_unstable(); black_diff.into_iter().take_while(|&black_d| { if black_add >= black_d { black_add -= black_d; true } else { false } }).count() as i32 } }